<script setup lang="ts">
const supabase = useSupabaseClient<any>()
const context = ref<any>(null), loading = ref(true), message = ref('')
const member = reactive({ email: '', role: 'member' })
const provider = reactive({ provider: 'github', client_id: '', client_secret: '' })
const referral = reactive({ label: '', max_uses: 1, expires_in_days: 30 })
const issuedReferral = ref('')
const isAdmin = computed(() => ['owner', 'admin'].includes(context.value?.role))
async function authed<T>(url: string, options: any = {}) { const { data: { session } } = await supabase.auth.getSession(); return $fetch<T>(url, { ...options, headers: { ...(options.headers || {}), ...(session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {}) } }) }
async function load() { loading.value = true; try { context.value = await authed('/api/adaptive/context') } finally { loading.value = false } }
async function addMember() { message.value = ''; try { const result: any = await authed('/api/adaptive/members', { method: 'POST', body: member }); message.value = `${result.member.email} joined as ${result.member.role} and inherited passport v${result.member.inherited_passport_version}.`; member.email = '' } catch (e: any) { message.value = e?.data?.message || e?.message || 'Unable to add member.' } }
async function saveProvider() { message.value = ''; try { await authed('/api/connectors/admin/provider-config', { method: 'POST', body: provider }); message.value = `${provider.provider} is now delegated to organization members.`; provider.client_id = ''; provider.client_secret = ''; await load() } catch (e: any) { message.value = e?.data?.message || e?.message || 'Unable to save provider configuration.' } }
async function createReferral() { message.value = ''; issuedReferral.value = ''; try { const result: any = await authed('/api/access/referrals', { method: 'POST', body: referral }); issuedReferral.value = result.referral.code; message.value = `Referral created for ${result.referral.max_uses} founder${result.referral.max_uses === 1 ? '' : 's'}. Copy it now; Madeus stores only its hash.`; referral.label = '' } catch (e: any) { message.value = e?.data?.message || e?.message || 'Unable to create a referral.' } }
async function copyReferral() { if (!issuedReferral.value || !import.meta.client) return; await navigator.clipboard.writeText(issuedReferral.value); message.value = 'Referral copied. Share it only with the intended founder.' }
async function replay(step: any) { const result: any = await authed('/api/adaptive/onboarding/replay', { method: 'POST', body: { step_id: step.id } }); await navigateTo(result.route) }
function status(step: any) { return context.value?.onboarding?.find((item: any) => item.step_id === step.id)?.status || 'available' }
onMounted(load)
</script>
<template><section class="mt-5 rounded-xl border bg-white p-4"><div class="flex flex-wrap items-start justify-between gap-3"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-purple-600">Organizational capability passport</div><h2 class="mt-1 text-sm font-semibold">{{ context?.organization?.name || 'Organization' }}</h2><p class="mt-1 text-xs text-gray-500">Members inherit approved connectors, policies, permissions, objectives, and the same replayable training path.</p></div><span v-if="context" class="rounded-full bg-purple-50 px-2 py-1 text-[10px] text-purple-700">{{ context.role }} · passport v{{ context.passport?.version }} · {{ context.member_count }} member{{ context.member_count === 1 ? '' : 's' }}</span></div><div v-if="loading" class="mt-3 text-xs text-gray-400">Loading organizational context…</div><template v-else-if="context"><div class="mt-4 grid gap-3 lg:grid-cols-3"><article v-for="step in context.passport?.training_path || []" :key="step.id" class="rounded-lg border p-3"><div class="flex items-center justify-between"><span class="text-xs font-medium">{{ step.label }}</span><span class="text-[9px]" :class="status(step) === 'completed' ? 'text-emerald-600' : 'text-gray-400'">{{ status(step) }}</span></div><button class="mt-2 text-[10px] text-blue-600" @click="replay(step)">Open or replay →</button></article></div><div class="mt-4 border-t pt-4"><form class="rounded-lg border border-emerald-200 bg-emerald-50/40 p-3" @submit.prevent="createReferral"><div class="flex flex-wrap items-start justify-between gap-3"><div><h3 class="text-xs font-semibold">Refer an AI-native founder</h3><p class="mt-1 text-[10px] text-gray-500">Issue a limited, expiring code. The recipient still grants their own accounts and permissions.</p></div><button class="rounded-lg bg-gray-900 px-3 py-2 text-xs text-white">Create referral</button></div><div class="mt-3 grid gap-2 sm:grid-cols-[1fr_90px_110px]"><input v-model="referral.label" maxlength="120" placeholder="Private label (optional)" class="rounded-lg border bg-white px-3 py-2 text-xs"><input v-model.number="referral.max_uses" type="number" min="1" max="10" aria-label="Maximum uses" class="rounded-lg border bg-white px-3 py-2 text-xs"><select v-model.number="referral.expires_in_days" aria-label="Referral expiry" class="rounded-lg border bg-white px-2 py-2 text-xs"><option :value="7">7 days</option><option :value="30">30 days</option><option :value="90">90 days</option></select></div><div v-if="issuedReferral" class="mt-3 flex items-center gap-2 rounded-lg bg-gray-950 p-3 text-white"><code class="min-w-0 flex-1 truncate text-xs">{{ issuedReferral }}</code><button type="button" class="rounded bg-white/10 px-2 py-1 text-[10px]" @click="copyReferral">Copy once</button></div></form></div><div v-if="isAdmin" class="mt-4 grid gap-4 border-t pt-4 lg:grid-cols-2"><form @submit.prevent="addMember"><h3 class="text-xs font-semibold">Add an existing Orchestrator user</h3><p class="mt-1 text-[10px] text-gray-500">Their role inherits this passport; familiar navigation remains unchanged.</p><div class="mt-2 flex gap-2"><input v-model="member.email" type="email" required placeholder="person@example.com" class="min-w-0 flex-1 rounded-lg border px-3 py-2 text-xs"><select v-model="member.role" class="rounded-lg border px-2 text-xs"><option value="member">Member</option><option value="operator">Operator</option><option value="reviewer">Reviewer</option><option value="engineer">Engineer</option><option value="analyst">Analyst</option><option value="admin">Admin</option></select><button class="rounded-lg bg-gray-900 px-3 text-xs text-white">Add</button></div></form><form @submit.prevent="saveProvider"><h3 class="text-xs font-semibold">Delegate an OAuth provider</h3><p class="mt-1 text-[10px] text-gray-500">Administrators configure the client once; members only grant account consent.</p><div class="mt-2 grid grid-cols-2 gap-2"><select v-model="provider.provider" class="rounded-lg border px-2 py-2 text-xs"><option v-for="item in ['google','microsoft','github','slack','atlassian','notion']" :key="item">{{ item }}</option></select><input v-model="provider.client_id" required autocomplete="off" placeholder="Client ID" class="rounded-lg border px-3 py-2 text-xs"><input v-model="provider.client_secret" type="password" autocomplete="new-password" placeholder="Client secret (blank retains current)" class="col-span-2 rounded-lg border px-3 py-2 text-xs"><button class="col-span-2 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white">Save delegated provider</button></div></form></div></template><p v-if="message" class="mt-3 rounded-lg bg-gray-50 p-2 text-xs text-gray-600">{{ message }}</p></section></template>
